"""
MKT Christ Commentary — 2 Kings chapters 18–20 (fill)
Run: python3 scripts/zc-christ-2kings-18-20-fill.py

Source data used:
- data/interlinear/2kings.json
- data/translation/draft/mediating/2kings.json

Key decisions in this range:
- Hezekiah treated as the typologically richest Judahite king before Christ: the closest approach
  to the Davidic ideal in the pre-exile period; his failures (tribute to Sennacherib, showing
  everything to Babylon, the "peace in my lifetime" response) mark the permanent gap that only
  Christ closes
- The Rabshakeh's challenge (18:19-35) read as a Christological type of Satanic temptation:
  targeting trust in YHWH, offering alternative security, and weaponizing the people's fear
- Hezekiah's prayer (19:14-19) compared to Gethsemane: both are royal prayers in extremity,
  brought before YHWH in the temple/in the garden
- 19:34 "for my own sake and for the sake of my servant David" treated as the dual Christological
  ground of deliverance: divine honor + Davidic covenant
- 20:19 Hezekiah's acquiescence to future punishment as the anti-type of vicarious suffering:
  a king who saves himself at the cost of future generations vs. Christ who sacrifices himself
  to save future generations
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS2 = {
  "18": {
    "1": '<p>Hezekiah\'s accession is synchronistically linked to Hoshea of Israel\'s third year, placing the two kingdoms on a shared timeline that makes the contrast unavoidable: Israel is in its final years; Judah under Hezekiah is about to experience its most dramatic divine deliverance. The synchronism is not merely chronological — it is theological. YHWH\'s governance of history places the faithful Davidic king and the apostate Northern king at the same historical moment, with opposite outcomes.</p>',
    "2": '<p>The biographical note — twenty-five years old, twenty-nine year reign — is part of the Davidic covenant record. Every king in the line is dated, named, with his mother noted: the genealogical chain that will produce Christ is maintained even through crisis and failure. Hezekiah\'s reign is one of Judah\'s most significant; the covenant community is not yet lost, because YHWH\'s purposes run through this king toward a greater David.</p>',
    "3": '<p>"He did what was right in the eyes of the LORD, just as his ancestor David had done." The superlative Davidic comparison — given to very few Judahite kings — marks Hezekiah as the closest approach to the Davidic ideal before the exile. Yet even this king falls short in tribute (v14), in showing Babylon his treasures (20:13), and in his self-regarding response to Isaiah\'s judgment (20:19). The gap between the best earthly David and the promised David is still wide; only Christ closes it completely (Acts 13:22–23).</p>',
    "4": '<p>The reform includes the destruction of Nehushtan — the bronze serpent Moses made (Num 21:8–9) that Israel had been burning incense to for centuries. Hezekiah\'s naming it "a piece of bronze" strips it of its accumulated sacred power. The type is profound: the serpent on the pole was itself a type of Christ (John 3:14 — "as Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up"), but the object that mediates a type cannot become an idol. When what points to Christ is worshipped instead of Christ, even YHWH\'s legitimate signs must be broken. Hezekiah\'s action is a shadow of Christ\'s own iconoclasm — the clearing of what has become an obstacle to genuine worship.</p>',
    "6": '<p><strong>Dāḇaq</strong> — "he clung to the LORD" — the covenant loyalty verb that appears in Deut 10:20 as the command for Israel to "cling to" YHWH. Hezekiah enacts what Israel was commanded to do and had failed to sustain. "He did not depart from following him; he kept the commandments the LORD had given Moses." The portrait is of a king who is what Israel was called to be. This is the closest the narrative comes to describing the inner disposition of Christ\'s own relationship with the Father — the son who does nothing except what the Father commands (John 8:28–29).</p>',
    "7": '<p>"The LORD was with him" — <em>Immanuel</em>, "God with us," is the theological claim of the Hezekiah narrative. It is also the name given to the child prophesied in Isa 7:14 — the sign to Ahaz (Hezekiah\'s father). The fulfillment of the Immanuel promise at the level of national deliverance in Hezekiah\'s reign is genuine but provisional: YHWH is "with" Hezekiah in the same way he was "with" David (1 Sam 18:14). The definitive <em>Immanuel</em> is the child born of Mary (Matt 1:23), in whom divine presence is not a conditional blessing but a permanent embodied reality.</p>',
    "8": '<p>Hezekiah\'s Philistine campaign — "from watchtower to fortified city" — extends Judah\'s territory toward the Davidic-Solomonic frontier. The military success is presented as a consequence of YHWH being "with him" (v7). The expansion of the covenant people\'s territory under a faithful king is a type of the expansion of Christ\'s kingdom — not through military conquest but through the proclamation of the gospel — to "the ends of the earth" (Acts 1:8), far beyond what any Judahite king achieved.</p>',
    "9": '<p>The date synchronism — Hezekiah\'s fourth year, Hoshea\'s seventh year — ties the Assyrian siege of Samaria directly to Hezekiah\'s chronology. The Northern kingdom falls while the Southern king is trusting. The narrative makes the contrast visible: the same Assyrian empire that destroys the faithless North will be repelled from the faithful South. This is the theological argument of the entire Hezekiah narrative — trust in YHWH produces outcomes that trust in military or political alternatives cannot.</p>',
    "10": '<p>Samaria falls in Hezekiah\'s sixth year. The Northern kingdom ends in the same era that Hezekiah is reforming the South. The contrast is stark and intentional: same imperial enemy, same historical moment, opposite fates — because of the difference in covenant posture. The remnant preserved in Judah becomes the continuation of the covenant community through which Christ will come. YHWH does not allow the entire covenant people to be destroyed because his promises run through them to their ultimate fulfillment.</p>',
    "11": '<p>The Assyrian deportation policy — scattering conquered peoples throughout the empire — is YHWH\'s covenant curse enacted through human instruments. "They did not obey the voice of the LORD" (v12) is the theological explanation. The scattering of Israel is the shadow of exile; its reversal — the ingathering of the scattered — is a central messianic promise (Isa 11:12; 43:5–6; Ezek 37:21). Christ is the one who gathers the scattered children of God into one (John 11:52).</p>',
    "12": '<p>"Because they did not listen to the voice of the LORD their God but violated his covenant." The exile is given its theological explanation: covenant unfaithfulness. The covenant mechanism of Deuteronomy (blessings for obedience, curses for disobedience) works exactly as promised. What Christ does for his people is absorb this covenant curse — "Christ redeemed us from the curse of the law by becoming a curse for us" (Gal 3:13) — so that the exile of sin becomes the homeland of grace.</p>',
    "13": '<p>Sennacherib invades and captures the fortified cities — forty-six, according to his own annals. The crisis of the remaining Judahite city-states mirrors the threat of total covenant collapse. Jerusalem alone stands between the Davidic line and extinction. The narrative places the covenant promise under maximum pressure: the only thing protecting the lineage of Christ is the miraculous intervention of YHWH in the face of the world\'s greatest military power.</p>',
    "14": '<p>Hezekiah\'s tribute — "I have sinned; withdraw from me and I will pay whatever you impose" — is a moment of political capitulation that the narrative does not endorse. The best Davidic king, under pressure, uses temple and palace treasures to buy off the enemy. Even the godliest earthly king cannot permanently secure the covenant community through political means. Only Christ\'s single offering, which cannot be depleted or repeated, permanently secures his people (Heb 10:14).</p>',
    "15": '<p>All the silver from the temple and treasury handed over to Sennacherib. The sacred resources of YHWH\'s house are spent on human security — an inversion of the covenant order in which YHWH provides security for those who maintain his house. The pattern of trading divine resources for human safety reaches its anti-type in Christ, who surrenders everything — including his life — not to purchase safety but to purchase a people whom God will keep forever safe (John 10:28–29).</p>',
    "16": '<p>Hezekiah strips the gold he himself had overlaid on the temple doors and doorposts. The reforming king who had enriched the temple now despoils it under duress. The temple\'s vulnerability to depletion — whether by enemies (1 Kgs 14:26) or by political necessity — is the chronic problem of a sacred space made of earthly materials. The new temple — Christ\'s body — cannot be stripped; the resurrection restores what crucifixion destroys (John 2:19–21).</p>',
    "17": '<p>Three Assyrian officials arrive with a great army at the Upper Pool — the same location where Isaiah confronted Ahaz in the Immanuel oracle (Isa 7:3). The geographic echo is intentional: the crisis of the Immanuel narrative reaches its resolution here. What Ahaz refused to trust — YHWH\'s protective presence — is what Hezekiah will demonstrate in the coming chapters. The three officials represent the full apparatus of Assyrian power: military, administrative, diplomatic. Against this stands the word of YHWH through Isaiah.</p>',
    "18": '<p>Three Judahite officials meet the Assyrian delegation. Eliakim (palace administrator), Shebna (secretary), Joah (recorder) — the institutional mediators of the Davidic government. The encounter is an embassy meeting, protocol governing the conversation. Yet the Rabshakeh will shortly abandon protocol (v28) and address the people directly — stripping away the diplomatic layer to reach the heart of the city. The pattern of power that bypasses institutions to speak directly to individual trust anticipates the gospel, which also speaks directly past institutional religion to the individual\'s dependence on God.</p>',
    "19": '<p>The Rabshakeh\'s central challenge: "What is the basis of your confidence?" The attack is theological: he targets <em>bāṭaḥ</em> (trust) — the same word that describes Hezekiah\'s relationship with YHWH (v5). The challenge is not primarily political but spiritual: "What are you depending on?" This is the same question at the heart of every temptation — the same question Satan posed to Jesus in the wilderness (Matt 4:1–11). The answer Christ gives — "man does not live by bread alone … you shall not put the Lord your God to the test … you shall worship the Lord your God and him only shall you serve" — is the answer Hezekiah\'s actions in ch19 embody.</p>',
    "20": '<p>"Strategy and military strength" (<em>ʿēṣāh ûgᵉḇûrāh</em>) — the Rabshakeh names the two resources Judah might claim: political wisdom and military power. Both are "empty words" in his assessment. The dismissal is accurate: Judah cannot match Assyria in either. The gospel\'s claim is similar — not that wisdom and power are wrong, but that "the foolishness of God is wiser than human wisdom, and the weakness of God is stronger than human strength" (1 Cor 1:25). Hezekiah\'s trust in YHWH is precisely the "foolishness" the Rabshakeh mocks.</p>',
    "21": '<p>Egypt as "a broken reed" that pierces the hand of anyone who leans on it. The image is visceral: seeking military support from a weak ally turns the support into the wound. The entire prophetic tradition concurs (Isa 30:1–5; Ezek 29:6–7). Against the broken reed of human alliance, YHWH offers himself as the rock (Ps 18:2; 62:2) — the one support that does not collapse, give way, or turn against the one who leans on it. Christ is the fulfillment of this promise: "Come to me, all you who are weary and burdened, and I will give you rest" (Matt 11:28) — not a reed but a yoke that is "easy" and a burden that is "light."</p>',
    "22": '<p>The Rabshakeh\'s ironic reading of Hezekiah\'s reforms: removing the high places was not faithfulness to YHWH but offense against him. The argument deliberately inverts the Deuteronomic logic. This pattern — twisting the meaning of genuine faithfulness to make it look like sin — is the characteristic move of the false teacher. Satan quotes Psalm 91 to Jesus (Matt 4:6), using scripture to tempt the one scripture is about. The Rabshakeh uses the language of covenant concern to undermine covenant trust.</p>',
    "23": '<p>Two thousand horses if Hezekiah can provide riders — the military weakness of Judah is exposed by the arithmetic. The Rabshakeh offers horses he knows Judah cannot use. The irony is that Hezekiah\'s strength is precisely not military; his "horses and chariots" are the word of YHWH (19:14: the horses and chariots of Israel — the phrase Elisha had used). The new covenant community is similarly equipped: not with visible force but with the "armor of God" (Eph 6:10–18) and the "sword of the Spirit, which is the word of God."</p>',
    "24": '<p>"How can you repel even one of the least of my master\'s officers?" The rhetorical escalation presses the point: Judah is militarily helpless. The argument is irrefutable at the military level. This is exactly the situation that makes YHWH\'s deliverance in 19:35 so decisive — 185,000 Assyrians struck by a single angel. The one who is "weak" in the world\'s terms overwhelms the strong through YHWH\'s power (1 Cor 1:27–28). The cross is the ultimate version of this pattern: military-level helplessness transformed into cosmic victory.</p>',
    "25": '<p>"The LORD himself told me: Go up against this land and destroy it." Whether this is propaganda, a distorted memory of an actual oracle, or a genuine Assyrian claim, the narrator does not clarify — because the important point is what happens next. YHWH\'s answer (19:20–34) does not validate the Rabshakeh\'s claim; it refutes it definitively. The false use of divine authority to justify destruction of God\'s people is the pattern of the antichrist (2 Thess 2:4); the true word of God addresses and dismantles the claim.</p>',
    "26": '<p>Eliakim and Shebna request that the Rabshakeh speak Aramaic — the language that would confine the conversation to the diplomatic channel and prevent the people from hearing. The request reveals that the officials understand what the Rabshakeh is doing: his goal is not negotiation but the psychological dissolution of the city\'s resolve. The attempt to keep dangerous words from ordinary people also appears in Acts 4:17 — "that it spread no further among the people" — and in every suppression of the gospel\'s public proclamation.</p>',
    "27": '<p>The Rabshakeh refuses — his message is precisely for the people. He uses graphic language of siege (eating dung, drinking urine) to make the cost of resistance visceral and personal. His target is not the officials but the city\'s resolve. The strategy is to make trust in YHWH feel like a king making his people suffer for his own pride. The same inversion of faith and self-destruction is the fundamental charge against every faithful person who refuses to capitulate to power. Jesus himself faced this: "He saved others; himself he cannot save" (Matt 27:42).</p>',
    "28": '<p>The Rabshakeh\'s public proclamation — standing and shouting in Hebrew at the wall. The formal public address bypasses official channels to reach the people directly. The city is forced to hear the case against their trust. The Rabshakeh\'s speech is a sustained argument that YHWH cannot deliver Jerusalem — the exact opposite of the gospel, which is the public proclamation that YHWH has delivered his people through the one Jerusalem executed (Acts 2:23–24). Both proclamations require a decision from the hearers.</p>',
    "29": '<p>"He cannot rescue you from my hand" — the flat denial of YHWH\'s capacity to deliver. The argument is empirical and inductive: no king has saved a city from Assyria; Hezekiah is no exception; YHWH is irrelevant. The gospel answers this argument not with counter-rhetoric but with the resurrection: YHWH did deliver his people from the ultimate power of death through Christ, demonstrating that the empirical evidence of universal human mortality was not the final word.</p>',
    "30": '<p>"Don\'t let Hezekiah persuade you to trust in the LORD." The three-part argument against trust in YHWH is complete: don\'t trust in Egypt; don\'t trust in Hezekiah; don\'t trust in YHWH. The third element is the most audacious — the direct attack on the covenant relationship. The temptation in the wilderness follows the same logic: "If you are the Son of God…" (Matt 4:3, 6) — the challenge to act on the basis of divine promise. Trust in the unseen promise against visible threat is the fundamental posture of faith, from Abraham to Hezekiah to Christ.</p>',
    "31": '<p>"Make peace with me and surrender" — the covenant parody. The terms offered — each under his own vine and fig tree — deliberately invoke the Solomonic prosperity language (1 Kgs 4:25) and the Micah/Isaiah eschatological vision (Mic 4:4; Isa 36:16). The Rabshakeh offers the covenant blessings under Assyrian patronage rather than under YHWH\'s covenant. This is the pattern of counterfeit peace: the world offers what only Christ can give (John 14:27 — "my peace I give you … not as the world gives"), at a price that destroys the covenant relationship.</p>',
    "32": '<p>"A land like your own" — the land promise co-opted for deportation. The covenant vocabulary of promised land is used to describe Mesopotamian exile. The theological audacity is remarkable: the Rabshakeh reframes captivity as the promised inheritance. The new covenant\'s answer is that the true inheritance is "imperishable, undefiled, and unfading, kept in heaven" (1 Pet 1:4) — no earthly power can replicate, confiscate, or counterfeit it.</p>',
    "33": '<p>"Has any god of the nations ever rescued his land from the king of Assyria?" The comparative theological argument: empirical evidence from the catalogue of conquest demonstrates that national deities cannot save. The argument is logically valid if YHWH is merely a national deity. The answer that will come (19:15) is that YHWH is not — he is God of heaven and earth, the maker of all kingdoms, including Assyria. The Rabshakeh\'s logical framework is the wrong category for YHWH.</p>',
    "34": '<p>Hamath, Arpad, Sepharvaim, Hena, Ivvah — the roll call of defeated cities and their gods. No national deity has stood. The catalog makes YHWH look like the next on the list. The gospel\'s claim is that YHWH alone stood — not just against Sennacherib but against death, sin, and the power of the demonic — because he is categorically different from every other claimant to divine status (Isa 46:5–7).</p>',
    "35": '<p>"Which of all the gods of these lands has rescued his territory from me?" The rhetorical climax of the Rabshakeh\'s speech. "How then will the LORD rescue Jerusalem from my hand?" The argument is complete. And then the narrative answers it, definitively, in 19:35: one angel, one night, 185,000 dead. The gap between the question and the answer is the structural form of faith: the challenge is complete before the deliverance is visible. YHWH demonstrates not just power but the specifically redemptive character of his power — he saves when the argument against saving is at its strongest.</p>',
    "36": '<p>The people\'s silence — commanded by the king and maintained by the people — is one of the narrative\'s most charged moments. Against the Rabshakeh\'s comprehensive and compelling address, the city says nothing. The silence is not defeat but disciplined trust. It is the antithesis of capitulation; it is the refusal to accept the frame of the challenge. Christ before Pilate maintains a similar silence (Matt 27:12–14): "He gave him no answer, not even to a single charge, so that the governor was greatly amazed." The silence of the one who trusts is more powerful than any counter-argument.</p>',
    "37": '<p>The three officials return to Hezekiah with torn clothes — the report of crisis brought to the king. The sequence — threat arrives, officials bring it to the king, king brings it to the temple — is the proper covenant pattern. The crisis is not suppressed but submitted to YHWH through prayer. Every element of the Hezekiah narrative in 18–19 is structured to show that the right response to imperial power is not military counter-mobilization but the posture of the covenant community before its God — bringing the enemy\'s words into the temple and laying them before YHWH.</p>'
  },
  "19": {
    "1": '<p>Hezekiah\'s immediate response — torn clothes, sackcloth, going to the house of the LORD — is the complete penitential posture. The king does not convene a war council or send for military reinforcements; he goes to the temple. This is the Christological pattern: the one who faces the ultimate crisis brings it before the Father in prayer. Gethsemane echoes this pattern — the night before the cross, Jesus goes not to organize resistance but to pray, in anguish, to his Father (Luke 22:41–44).</p>',
    "2": '<p>The delegation to Isaiah — Eliakim, Shebna, the senior priests in sackcloth — is a formal prophetic consultation. Hezekiah needs the word of YHWH, not just human counsel. The pattern of bringing the national crisis to the prophet — the mediator of YHWH\'s word — anticipates the new covenant order in which the risen Christ is himself both king and prophet, whose word addresses every crisis from within the community he leads.</p>',
    "3": '<p>"Children have come to the opening of the womb, but there is no strength to give birth" — the crisis at its most acute: maximum vulnerability, no capacity to complete what has been started. The image is of a birth that cannot occur — the nation\'s survival hanging at the point of crisis with no human power to resolve it. The gospel is addressed precisely to this situation: "While we were still helpless, at the right time Christ died for the ungodly" (Rom 5:6). The helplessness is the condition that makes grace the only logic.</p>',
    "4": '<p>"Perhaps the LORD your God will hear" — the proper tentativeness of the prayer approach. Hezekiah does not presume; he hopes. The formula "the living God" (<em>ʾĕlōhîm ḥayyîm</em>) is the counter to the Rabshakeh\'s catalog of dead idols. YHWH is categorically alive in a way no national deity is: he hears, responds, acts. This life reaches its definitive expression in Christ, who is "the resurrection and the life" (John 11:25) — not merely a living deity but life itself in person.</p>',
    "5": '<p>A brief hinge verse — the servants arrive at Isaiah. The prophet is accessible; the word of YHWH is available at the moment of crisis. The availability of the word in extremity is a shadow of Christ\'s own constant accessibility: "Come to me, all who labor and are heavy laden" (Matt 11:28) — the Son of God is not hard to find when the crisis is real.</p>',
    "6": '<p>"Do not be afraid because of the words you have heard" — the oracle of salvation opens with the divine prohibition of fear. This formula (<em>ʾal-tîrāʾ</em>) appears throughout Isaiah\'s oracles (Isa 7:4; 41:10; 43:1) and in Christ\'s own repeated assurances to his disciples (Matt 14:27; 28:10; John 14:27; Rev 1:17). The words of the Rabshakeh — comprehensive and seemingly unanswerable — are answered first not by a counter-argument but by a divine "do not be afraid." The fear must be displaced before the deliverance can be received.</p>',
    "7": '<p>YHWH will "put a spirit" in Sennacherib — a directing influence that will make him hear a report and return home, where he will die by the sword. The divine sovereignty over the inner life of the enemy king is the first element of the deliverance plan. The Rabshakeh\'s confident mastery of his world — his surveys, his arguments, his conquests — is subject to a single divine redirection. Christ similarly redirects the powers that oppose his people, using even their hostility for redemptive purposes (Acts 2:23: "delivered up according to the definite plan and foreknowledge of God … you crucified and killed").</p>',
    "8": '<p>The Rabshakeh returns to find Sennacherib at Libnah — the campaign has shifted. The gap between the first Assyrian address and the second letter creates narrative space: Sennacherib\'s plan is not as fixed as his rhetoric implied. The mighty empire is already in motion according to YHWH\'s purposes (v7: the "spirit" has already been placed). The deliverance is underway before Hezekiah even knows it.</p>',
    "9": '<p>Tirhakah of Ethiopia arrives as a military threat to Sennacherib — YHWH\'s indirect means of pressure on the empire. The geopolitical movement of a distant African kingdom becomes an instrument of Jerusalem\'s rescue. YHWH\'s sovereignty extends to kings who do not know him; his purposes coordinate the actions of distant empires without those empires knowing they are serving a divine plan. The incarnation is the ultimate coordination: Rome, Herod, and the religious authorities all act "according to the definite plan and foreknowledge of God" (Acts 2:23).</p>',
    "10": '<p>"Do not let your God, in whom you are trusting, deceive you." The second Assyrian communication intensifies the theological target — now it is YHWH directly who is accused of deception. The argument implies that Hezekiah\'s trust in YHWH is a form of self-deception being perpetuated by a weak deity. This is the ultimate challenge to covenant faith: not that God is absent but that he is a liar. The gospel\'s answer is the resurrection — YHWH\'s promise of life through the Son was not deception but truth (John 11:25; 2 Cor 1:20: "all the promises of God find their Yes in him").</p>',
    "11": '<p>The catalog of Assyrian destruction — "utterly destroying them" (<em>ḥᵉrēm</em>) — is offered as irrefutable historical evidence. The Rabshakeh\'s argument from historical precedent is the strongest possible: it has happened everywhere else. The only thing that could break this induction is an event that breaks the pattern entirely. The resurrection of Christ breaks the ultimate pattern — death has always won; now it has not. The Hezekiah narrative is a type of this: the pattern of Assyrian inevitability is broken precisely because YHWH acts where no precedent exists.</p>',
    "12": '<p>The gods of Gozan, Haran, Rezeph, and Eden all failed. The argument is complete: no deity, anywhere, has resisted Assyria. YHWH is being placed in a category with those deities. The theological breakthrough of Hezekiah\'s prayer (19:15–19) is to argue that YHWH is not in that category — he is the God who made the category, including the nations whose gods failed. Christ\'s victory over death similarly argues from outside the category: death cannot hold the one through whom all things were made (John 1:3; Acts 2:24).</p>',
    "13": '<p>"Where are the kings of Hamath, Arpad, Sepharvaim, Hena, and Ivvah?" — rhetorical question expecting the answer "gone." The kings fell with their cities and gods; the political order that sustained their rule collapsed. Only one king is not gone: the Davidic king, whose dynasty YHWH has promised will not end (2 Sam 7:16). The persistence of the Davidic line through every imperial assault is itself a Christological sign — YHWH will not allow the lineage to be extinguished, because it must produce the eternal king.</p>',
    "14": '<p>Hezekiah spreads the letter before the LORD in the temple — laying the enemy\'s words before the one who can answer them. The physical act of bringing a threatening letter into the presence of God and spreading it out is prayer through enacted metaphor: "You read it; you answer it." The closest parallel in Jesus\'s ministry is Gethsemane — the Son spreads his full crisis before the Father (Luke 22:42: "Father, if you are willing, remove this cup from me. Nevertheless, not my will, but yours, be done"). Both prayers bring the full weight of the threat into the divine presence rather than attempting human resolution.</p>',
    "16": '<p>"Incline your ear, LORD, and hear; open your eyes, LORD, and see." The anthropomorphic petition invites divine attention to a specific situation. The doubling — ear and eye, hear and see — is the rhetoric of urgency: attend to this, in all its dimensions. "Words Sennacherib has sent to mock the living God" — the prayer reframes the Assyrian threat as blasphemy against YHWH rather than as a military threat against Judah. The reframing is crucial: if this is YHWH\'s honor that is at stake, then rescue is not merely Judah\'s benefit but the necessary demonstration of who YHWH is.</p>',
    "17": '<p>Hezekiah concedes the historical facts — Assyria has destroyed the nations. The prayer does not dispute the evidence; it reinterprets it. This is the move of faith under pressure: acknowledging what is visibly true while holding to what is invisibly true. The cross looks like defeat; the gospel concedes the death and claims the resurrection. Honest faith does not suppress the evidence of crisis but understands it within a larger frame.</p>',
    "18": '<p>"For those were no gods at all, merely human handiwork, wood and stone." The theological axiom: the nations Assyria destroyed had deities who could not help them because those deities were human artifacts. The logical distinction between made gods and the making God is the hinge of Hezekiah\'s prayer. Only YHWH is not made; therefore only YHWH\'s help is structurally available where made gods fail. Christ as "the image of the invisible God" (Col 1:15), "through whom all things were made" (John 1:3), is the one who is not within the category of what can be destroyed.</p>',
    "19": '<p>"Deliver us from his hand, so that all the kingdoms of the earth may know that you, LORD, are God alone." The petition is explicitly missional: rescue serves testimony. Hezekiah prays not only for Judah\'s survival but for the nations\' knowledge of YHWH. The same logic governs the incarnation: Christ comes not merely to rescue Israel but "so that all the kingdoms of the earth may know" — that the light shines in the darkness (John 1:5), that the word goes out to all nations (Matt 28:19), that "every knee should bow … and every tongue confess that Jesus Christ is Lord" (Phil 2:10–11).</p>',
    "20": '<p>Isaiah\'s response: "I have heard your prayer about Sennacherib king of Assyria." The specific, named answer — the prayer is identified, heard, and answered. "I have heard" (<em>šāmaʿtî</em>) is YHWH\'s own word, the counter to every claim that the living God does not hear. Christ is the mediator who brings prayer before the Father and secures the answer: "And I know that you always hear me" (John 11:42 — Jesus, at Lazarus\'s tomb) and "Ask, and you will receive, that your joy may be complete" (John 16:24).</p>',
    "21": '<p>"The virgin daughter of Zion despises and mocks you; the daughter of Jerusalem wags her head behind you." Jerusalem is portrayed as a woman who laughs at the would-be conqueror — not in defiance but in the confidence that his power is exposed as empty. The mocking of Sennacherib is the reversal of the Rabshakeh\'s mockery of Judah. YHWH\'s oracle turns the empire\'s contempt back on itself. The eschatological image of the proud who mock God being humiliated before his reign is present throughout the Psalms (Ps 2:4; 37:13) and finds its fulfillment in Christ\'s resurrection, which makes all opposition to his kingship retroactively absurd.</p>',
    "22": '<p>"Against whom have you raised your voice and lifted your eyes in pride? Against the Holy One of Israel!" The identification of YHWH as the Holy One of Israel — Isaiah\'s characteristic title — makes Sennacherib\'s arrogance not merely political overreach but theological category error. To boast against YHWH is to boast against the one whose holiness defines the standard by which all claims to power are measured. Christ, as the embodiment of YHWH\'s holiness in human form (John 6:69: "the Holy One of God"), is the one before whom every boast ultimately falls silent.</p>',
    "23": '<p>Sennacherib\'s boasts — many chariots, climbing the heights of Lebanon, cutting its cedars — are quoted back to him by YHWH as evidence against him. The empire\'s self-glorification is heard and registered. The specific military boasts are the substance of the charge. This pattern — the oppressor\'s own words becoming the evidence for his judgment — recurs in the prophetic tradition (Ezek 28:2–10; Isa 14:12–15) and in the apocalyptic reversal of Babylon (Rev 18:7: "As she glorified herself and lived in luxury, so give her a like measure of torment").</p>',
    "24": '<p>"I dried up all the streams of Egypt" — the hyperbolic boast of mastery over the created order. The empire claims to have altered hydrology through military might. The oracle\'s implicit answer is: only YHWH actually does this (Exod 14:21–22; Ps 74:15; Isa 11:15). The claims of empire imitate the acts of God without being able to produce them; Christ alone actually speaks to the waters, and they obey him (Mark 4:39).</p>',
    "25": '<p>"Have you not heard? Long ago I determined this; from ancient times I planned it." YHWH declares that Sennacherib\'s conquests were YHWH\'s own prior plan — not Assyrian achievement but divine instrument. The sovereignty claim reframes the entire narrative: the empire\'s greatest victories were YHWH\'s foreordained purposes. This is the pattern of the cross: those who crucified Jesus acted according to "the definite plan and foreknowledge of God" (Acts 2:23). The worst act in history was the most precisely planned act in history — planned "before the foundation of the world" (Rev 13:8).</p>',
    "26": '<p>"That is why their inhabitants had so little power — they were shattered and ashamed." The conquered nations were defeated because YHWH had decreed it — their weakness was the result of his sovereign purpose, not the mere superiority of Assyrian arms. The reversal: Assyria, which felt invincible, will now be broken by YHWH\'s word alone (19:35). The one who breaks nations will be broken; the one who seemed weak (Jerusalem, the remnant, the crucified) will stand. The grass on the rooftop that the empire\'s victims resemble — rootless, scorched — becomes the image of the empire itself.</p>',
    "27": '<p>"But I know where you live and when you come and go, and I know your rage against me." The divine omniscience over Sennacherib is total — spatial, temporal, psychological. YHWH knows the rage that drives the empire; the empire does not know it is being watched. The same omniscience governs Christ\'s knowledge of his adversaries: "Jesus knew what was in man" (John 2:25); "he knew his betrayer" (John 13:11). The one who opposes Christ operates under full divine surveillance; the outcome is already determined.</p>',
    "28": '<p>"I will put my hook in your nose and my bridle in your mouth, and I will make you go back the way you came." YHWH reverses Assyria\'s own imperial method — the hook in the nose used on conquered kings (depicted on Assyrian palace reliefs) — and applies it to Sennacherib. The tools of domination become the instruments of humiliation. The cross itself works this reversal: the tool of Roman execution becomes the instrument of Satan\'s defeat (Col 2:15: "disarming the rulers and authorities … triumphing over them by the cross").</p>',
    "29": '<p>"This year you will eat what grows on its own … in the third year plant and harvest." The sign is agricultural and patient — three years of progressive restoration, normalizing into abundance. The three-year timeline in a farming context is not arbitrary: it takes that long to reestablish productive agriculture after a crisis. YHWH\'s promise is not a spectacular one-off miracle but the restoration of the ordinary rhythms of life. The new covenant\'s promise is similarly concrete: not just escape from death but "life, and life more abundantly" (John 10:10).</p>',
    "30": '<p>"The surviving remnant of the house of Judah will again take root downward and bear fruit upward." The remnant theology — the preserved portion of the covenant community — is Isaianic at its core (Isa 10:20–22; 11:11). "Take root downward" is the image of stability: not the rooftop grass (v26) but deeply rooted growth. "Bear fruit upward" is the image of flourishing: not mere survival but abundance. Christ is the true vine (John 15:1) in whom the remnant community takes its root; bearing fruit is the evidence of remaining in him.</p>',
    "31": '<p>"The zeal of the LORD of hosts will accomplish this." <em>Qinʾat YHWH ṣᵉḇāʾôt</em> — divine passion as the engine of restoration. The same phrase appears in Isa 9:7, applied to the promised heir of David\'s throne whose government "will be established with justice and righteousness … from this time forth and forevermore." The zeal of YHWH that defends Jerusalem against Sennacherib is the same zeal that will establish the eternal Davidic kingdom through Christ. The energy is not different; only the scale and permanence differ.</p>',
    "32": '<p>YHWH\'s fourfold no to Sennacherib — no entry into the city, no arrow shot here, no shield set before it, no siege ramp built against it. Each element is a specific military tactic; the prohibition is technically comprehensive. The city is protected not by its walls or garrison but by YHWH\'s word. The new Jerusalem — the city of the living God (Heb 12:22) — is protected by the same word permanently; "nothing unclean will ever enter it, nor anyone who does what is detestable or false, but only those who are written in the Lamb\'s book of life" (Rev 21:27).</p>',
    "33": '<p>"He will go back the same way he came." The direction of the invasion is reversed by YHWH\'s decree. The direction of history — toward the destruction of Jerusalem — is turned back by a single divine word. This is the pattern of Christ\'s resurrection: the direction of death is reversed. The tomb is not just empty; it is the place from which the Lord goes forward, not back. The Assyrian withdrawal is a type of every reversal that YHWH\'s word enacts against the powers of destruction.</p>',
    "34": '<p>"I will defend this city and save it, for my own sake and for the sake of my servant David." The dual motivation is structurally significant. "For my own sake" (<em>lᵉmaʿănî</em>): YHWH\'s name and honor are bound up with Jerusalem\'s survival. "For the sake of my servant David" (<em>lᵉmaʿan dāwid ʿaḇdî</em>): the Davidic covenant obligates YHWH to protect the city of David\'s line. Both motivations converge in Christ: God is glorified in the Son (John 13:31–32), and the Davidic covenant is fulfilled in him (Luke 1:32–33). The defense of Jerusalem prefigures the defense of Christ\'s people — guaranteed by who YHWH is and what he has promised.</p>',
    "35": '<p>One angel, one night, 185,000 dead. The divine warrior needs no army, no siege, no strategy — a single divine agent accomplishes what no human force could achieve. The morning reveals "all dead bodies." YHWH\'s deliverance is total and effortless at the divine level — while requiring no human military action from Judah at all. The resurrection works with the same economy: one event, one night-to-morning, the power of death decisively broken. The angel of the Lord who strikes the Assyrian camp is a type of the power of God that rolled the stone away and raised the Son from the dead (Matt 28:2).</p>',
    "36": '<p>Sennacherib breaks camp and returns to Nineveh. The most powerful king in the world simply goes home. The contrast with his elaborate rhetorical assault (18:19–35) and the narrative of his departure (a single compound verb: "he broke camp, withdrew, returned") could not be starker. The boaster is silenced; the empire retreats. The eschatological promise is that every enemy of God\'s people will ultimately face this same reversal — the rhetoric of opposition will give way to the silence of retreat before the risen Lord.</p>',
    "37": '<p>Sennacherib is killed by his own sons in the temple of his god Nisroch. He who mocked the living God dies before a dead idol, killed by members of his own household. The irony is the narrative\'s theological verdict: the idol worshipped in life provides no protection in death; the family that should be his security becomes his assassins. The prophecy of 19:7 — "I will cause him to fall by the sword in his own land" — is fulfilled exactly. The God who said Sennacherib would fall by the sword ensured it; the reliability of YHWH\'s word is the permanent counterpart to the unreliability of every other claim to ultimate sovereignty.</p>'
  },
  "20": {
    "1": '<p>Hezekiah becomes mortally ill — "at the point of death." The man who trusted YHWH against Sennacherib now faces an enemy that no imperial might can address: his own mortality. Isaiah comes with the divine verdict: "Put your house in order; you will die, not live." Even the faithful Davidic king is mortal; even the king whom YHWH protected against empire cannot escape death without divine intervention. Christ alone is "the firstborn from the dead" (Col 1:18) — the one for whom death is not the final verdict but the penultimate chapter.</p>',
    "2": '<p>Hezekiah turns his face to the wall and prays. The physical turning away from human witnesses — turning toward YHWH alone — is the posture of desperate prayer. The wall is the boundary between the visible and the invisible; Hezekiah faces the invisible. Prayer in extremity that turns away from the available human resources and toward YHWH alone is the posture Christ models in Gethsemane (Matt 26:39: "going a little farther, he fell on his face and prayed").</p>',
    "3": '<p>"Remember how I have walked before you faithfully and wholeheartedly, and have done what is good in your sight." Hezekiah\'s prayer appeals to his record. The contrast with Christ\'s Gethsemane prayer is instructive: Jesus does not appeal to his own faithfulness but prays "your will be done" — not because he has no faithfulness to appeal to, but because his prayer is not a transaction but a surrender. Hezekiah\'s self-assessment is accurate (v3b: "he wept bitterly"); Christ\'s prayer is theologically deeper because it releases the outcome entirely to the Father\'s will.</p>',
    "4": '<p>The word of YHWH comes to Isaiah before he has even left the middle courtyard. The response is immediate — more immediate than normal prophetic channels. YHWH\'s answer to Hezekiah\'s prayer is not delayed. The immediacy of the divine response to the faithful king\'s prayer in extremity is a type of the Father\'s readiness to act: "Call upon me in the day of trouble; I will deliver you, and you shall glorify me" (Ps 50:15). The resurrection is YHWH\'s immediate reversal of the verdict of death on his Son.</p>',
    "6": '<p>"I will add fifteen more years to your life." YHWH gives more than the minimum — not just healing but a specific, generous extension. "And I will rescue you and this city from the hand of the king of Assyria, and I will defend this city." The individual healing is embedded in the corporate promise; Hezekiah\'s life and Jerusalem\'s protection are linked. Christ\'s resurrection similarly produces more than personal survival: it generates the church, fills the disciples with the Spirit, and opens salvation to the nations (Acts 2).</p>',
    "7": '<p>A poultice of figs applied to the boil — physical medicine within the miraculous healing. The use of ordinary means alongside divine action is characteristic of YHWH\'s economy: he works through burning bushes and donkeys and fish-full nets and fig poultices. The incarnation is the supreme version of this: God healing the world through the most ordinary of means — a human body, a carpenter from Galilee, a meal of bread and wine, water of baptism.</p>',
    "8": '<p>Hezekiah asks for a sign. The request for a sign after a divine promise is not unbelief (compare Gideon, Judg 6:36–40; compare Mary, Luke 1:34) — it is the proper seeking of a concrete divine marker that can anchor ongoing trust. Isaiah offers the choice of shadow going forward or backward — the sign\'s form leaves YHWH to determine the harder option. The giving of signs is YHWH\'s accommodation to human need for concrete anchors of faith; the resurrection is the ultimate sign, given not on request but in advance of the disciples\' full understanding.</p>',
    "9": '<p>The shadow on the sundial can advance ten steps or go backward ten steps — Isaiah offers the choice. The reversal of time\'s direction (the shadow going backward) is the harder, more dramatic option. It is also the more Christological: the resurrection is not just time extended but time reversed — death undone, not merely postponed. The backward movement of the shadow is a type of the resurrection\'s retroactive logic: what was done is undone; what was closed is opened; what went forward into death goes back into life.</p>',
    "10": '<p>Hezekiah chooses the shadow going backward — "it is easy for it to go forward; rather, let it go back ten steps." The choice reveals wisdom: he recognizes that the more dramatic sign is the more demanding request, and he asks for it. The willingness to ask for the harder thing — not just the extension of the normal but the reversal of the natural — is the posture of faith that matches the magnitude of the promise. The resurrection of Christ is the ultimate "backward" sign: the reversal of the natural order of death at the point of maximum human certainty that death had won.</p>',
    "11": '<p>YHWH makes the shadow go back ten steps on the staircase of Ahaz. The reversal of the shadow is YHWH\'s sovereignty over the created order — specifically over time, as marked by the movement of light. The darkness that covered the earth at the crucifixion (Mark 15:33) and the dawn of the resurrection morning are the cosmic counterparts: the created order responds to the death and resurrection of the Creator\'s Son. YHWH\'s governance of light and shadow from Ahaz\'s sundial to Golgotha\'s darkness is a continuous demonstration of the same sovereign power.</p>',
    "12": '<p>Merodach-Baladan of Babylon sends letters and a gift — having heard of Hezekiah\'s illness and recovery. The Babylonian king\'s interest is diplomatic: the anti-Assyrian coalition is gathering. Hezekiah\'s miraculous recovery has given him a new reputation in the international arena. The verse is transitional — introducing the Babylonian threat that will come long after Hezekiah\'s death. The narrative places the future threat\'s seed in the moment of Hezekiah\'s greatest miraculous blessing.</p>',
    "13": '<p>Hezekiah shows the Babylonian envoys everything — "the silver, the gold, the spices, the fine oil, his armory, all that was found in his storehouses. There was nothing in his palace or in all his realm that Hezekiah did not show them." The word "nothing" is the condemnation. The king who trusted YHWH against Sennacherib surrenders the temple and palace treasures to pride before the Babylonian delegation. The great failure of Hezekiah is not military but spiritual: he uses divine gifts for self-glorification rather than for YHWH\'s purposes. The contrast with Christ, who took "no account of being equal with God" and did not use divine gifts for self-display (Phil 2:6–7), is acute.</p>',
    "14": '<p>Isaiah comes immediately to Hezekiah: "What did these men say? Where did they come from?" The prophetic interrogation is not information-gathering but the form of the judgment that follows. Isaiah already knows; the question is Hezekiah\'s moment to recognize what he has done. "They came from Babylon" — the answer names the coming threat. The prophet\'s arrival after the diplomatic failure is the word of God entering the situation of human pride to pronounce its consequences.</p>',
    "15": '<p>Hezekiah\'s candid answer: "They saw everything in my palace. There was nothing among my storehouses that I did not show them." The complete disclosure — given to Isaiah as it was given to the Babylonians — is both honest and damning. The king who showed everything has nothing hidden from the prophet. The transparency that should have governed Hezekiah\'s relationship with YHWH has instead governed his diplomatic self-presentation. The gospel reverses this: "Nothing is hidden that will not be revealed" (Luke 12:2) — not as condemnation but as the ultimate transparency of a community that lives before God.</p>',
    "16": '<p>"Then Isaiah said to Hezekiah: Listen to the word of the LORD." The formula introduces judgment in prophetic speech: the narrative slows, the divine voice is about to speak consequence. Hezekiah, who heard the word of the LORD through Isaiah in rescue (19:6–7, 20–34), now hears it in warning. The word of YHWH addresses both deliverance and discipline; neither exhausts its reach. Christ himself pronounces both grace and judgment — the same mouth that says "come to me" also says "depart from me" (Matt 11:28; 7:23).</p>',
    "17": '<p>"Look — days are coming when everything in your palace, and everything your ancestors have stored up to this day, will be carried off to Babylon; nothing will be left, says the LORD." The Babylonian exile — over a century away — is prophesied precisely and specifically from the moment of Hezekiah\'s pride. The connection between Hezekiah\'s display and the future emptying of Jerusalem is direct: what he showed becomes what is taken. The principle of Deuteronomic consequence operates even at the temporal distance of generations. Christ takes this principle into himself: he absorbs the consequence, becoming the one who is "emptied" (Phil 2:7: <em>ἐκένωσεν</em>) so his people need not be.</p>',
    "18": '<p>"And some of your own descendants will be taken away and will become eunuchs in the palace of the king of Babylon." This is fulfilled in Daniel and his companions (Dan 1:3–7). The prophecy moves from the general (palace treasures) to the personal (Hezekiah\'s own descendants). The long reach of covenant consequence is demonstrated: Hezekiah\'s pride in 701 BC produces captive royal descendants in 605–586 BC. Yet even in that captivity, YHWH\'s purposes advance: Daniel in Babylon becomes the vehicle of divine revelation; Joseph in Egypt became the vehicle of preservation. YHWH\'s faithfulness works through the consequences of human failure as well as through human obedience.</p>',
    "19": '<p>Hezekiah\'s response: "The word of the LORD that you have spoken is good … will there not be peace and security in my lifetime?" The troubling element is the second sentence — "at least during my lifetime there will be peace." Hezekiah accepts future punishment as long as his own era is undisturbed. The contrast with vicarious suffering is stark: the faithful servant accepts present suffering for future others\' benefit; Hezekiah accepts future suffering as long as his own present is undisturbed. Christ\'s posture is the inverse: he accepts immediate death — the cross — so that future generations are permanently secured. Hezekiah\'s acquiescence to futurity is the anti-type of Christ\'s embrace of the present for the sake of all who come after.</p>',
    "20": '<p>Hezekiah\'s regnal close notes his great engineering achievement: the pool and tunnel that brought water into Jerusalem. The Siloam tunnel — archaeologically verified, with the workers\' inscription found in 1880 — is a genuine monument to human ingenuity and Hezekiah\'s foresight. The tunnel that brings water into the city to sustain it in siege is a shadow of Christ, who declares "let anyone who is thirsty come to me" (John 7:37–38) — the living water that flows not through rock but through the one who is himself the source.</p>',
    "21": '<p>Hezekiah dies, and Manasseh — the worst king in Judah\'s history — reigns in his place. The contrast is the narrative\'s final word on the limits of even the best earthly king: his succession is beyond his control. Hezekiah\'s faith and reform cannot be transmitted by heredity; Manasseh will undo everything and add more. Only Christ\'s kingdom produces successors of the same character as the king, because the king himself indwells his successors through the Spirit (John 14:17; 15:4). The failure of Hezekiah\'s succession is the permanent argument for why the kingdom needs a different king — one who does not merely reign for twenty-nine years and die, but reigns forever (Isa 9:7; Luke 1:33).</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', '2kings')
    merge_comm(existing, KINGS2)
    save_comm('mkt-christ', '2kings', existing)
    for ch in ['18', '19', '20']:
        print(f'  ch{ch}: {len(existing.get(ch, {}))} verses')

if __name__ == '__main__':
    main()
